"use strict";(self.webpackChunkTartaria=self.webpackChunkTartaria||[]).push([[910],{6646:(i,l,e)=>{e.r(l),e.d(l,{data:()=>a});const a={key:"v-65593a1f",path:"/wisdom/diff.html",title:"Пословица ≠ Поговорка",lang:"ru-RU",frontmatter:{sidebarDepth:2},excerpt:"",headers:[],filePathRelative:"wisdom/diff.md",git:{updatedTime:1727634452e3,contributors:[{name:"blackchestnut",email:"alexander.kalinichev@gmail.com",commits:2}]}}},2265:(i,l,e)=>{e.r(l),e.d(l,{default:()=>r});const a=(0,e(6252).uE)('<h1 id="пословица-поговорка" tabindex="-1"><a class="header-anchor" href="#пословица-поговорка" aria-hidden="true">#</a> Пословица ≠ Поговорка</h1><p>Пословица - грамматически законченное предложение, имеет повествовательный или побудительный характер. По структуре состоит из двух частей, которые являют собой противопоставление. Не более двенадцати слов.</p><p><em>Примеры:</em></p><ul><li>Гол как сокол, а остер как топор</li><li>Один в поле не воин, а путник</li><li>От работы кони дохнут, а люди — крепнут</li></ul><p>Поговорка - краткое высказывание, чаще образное чем буквальное. Не редко рифмованное, но главное - оставляет ощущение незаконченности.</p><p><em>Примеры:</em></p><ul><li>Как снег на голову</li><li>Когда рак на горе свистнет</li><li>Коса — девичья краса</li><li>Как до утки, на третьи сутки</li><li>Остаться у разбитого корыта</li><li>Подвести под монастырь</li><li>После дождичка в четверг</li><li>Семь пятниц на неделе</li><li>&quot;Наверное&quot; не всегда верное!</li></ul>',7),t={},r=(0,e(3744).Z)(t,[["render",function(i,l){return a}]])},3744:(i,l)=>{l.Z=(i,l)=>{for(const[e,a]of l)i[e]=a;return i}}}]);